      function CF_YEARFormula return Number is
begin
  RETURN(TRUNC(:INSURANCE_DAYS / 300));
end;

      function CF_MONTHSFormula return Number is
begin
  RETURN TRUNC((:INSURANCE_DAYS - (300 * :CF_YEARS)) /25);
end;

      function CF_DAYSFormula return Number is
begin
  RETURN(TRUNC(:INSURANCE_DAYS - (300 * :CF_YEARS) - (25 * :CF_MONTHS)));
end;

      function CF_YEARS_SUMFormula return Number is
begin
  RETURN(TRUNC(:P_TOTAL_DAYS / 300));
end;

      function CF_MONTHS_TOTALFormula return Number is
begin
  RETURN TRUNC((:P_TOTAL_DAYS - (300 * :CF_YEARS_TOTAL)) /25);
end;

      function CF_DAYS_TOTALFormula return Number is
begin
  RETURN(TRUNC(:P_TOTAL_DAYS - (300 * :CF_YEARS_TOTAL) - (25 * :CF_MONTHS_TOTAL)));
end;

      function CF_CALC_YEARSFormula return Number is
begin
  RETURN(TRUNC(:DAYS / 300));
end;

      function CF_CALC_MONTHSFormula return Number is
begin
  RETURN TRUNC((:DAYS - (300 * :CF_CALC_YEARS)) /25);
end;

      function CF_CALC_DAYSFormula return Number is
begin
  RETURN(TRUNC(:DAYS - (300 * :CF_CALC_YEARS) - (25 * :CF_CALC_MONTHS)));
end;

      function CF_CALC_YEARS_TOTALFormula return Number is
begin
  RETURN(TRUNC(:S_INS_DAYS_CALC_FINAL / 300));
end;

      function CF_CALC_MONTHS_TOTALFormula return Number is
begin
  RETURN TRUNC((:S_INS_DAYS_CALC_FINAL - (300 * :CF_CALC_YEARS_TOTAL)) /25);
end;

      function CF_CALC_DAYS_TOTALFormula return Number is
begin
  RETURN(TRUNC(:S_INS_DAYS_CALC_FINAL - (300 * :CF_CALC_YEARS_TOTAL) - (25 * :CF_CALC_MONTHS_TOTAL)));
end;

      function CF_FOR_CALC_DAYSFormula return Number is
begin
  IF :CS_CALC_MONTHS_TOTAL < 6 THEN
  	 RETURN :CS_CALC_YEARS_TOTAL;
  ELSE
  	 RETURN :CS_CALC_YEARS_TOTAL + 1;
  END IF;
  
  RETURN null;
end;

      function CF_KYRIOS_FOREASFormula return Char is
 v_title_code VARCHAR2(5); 
 v_value VARCHAR2(50);
 v_descr VARCHAR2(150);
begin
  
  
  IF :P_MAIN_ACCOUNT_TYPE = '2' AND NVL(:P_ACCOUNT_MAIN,0) != 0 THEN
     v_descr := 'ΝΠΔΔ';	
  ELSIF :P_MAIN_ACCOUNT_TYPE = '1' AND NVL(:P_ACCOUNT_MAIN,0) != 0 THEN 
  	 v_descr := 'ΙΚΑ';
  ELSE	
		  v_title_code := '00075'; 
			v_value:=  (FIND_FACT_SUB_DEATH_VARCHAR(:P_INSURED_NAME_IND,
							                            :P_DT_DECISION_YEAR_SR,
							                            :P_DT_DEC_UNIT_CODE_SR,
										                      :P_DT_INCR_SEC_NO_SR,
										                      '1',
										                      0,
											                    0,
											                    '00001',
											                    v_title_code,
											                    '00010'));
			IF v_value IS NOT NULL THEN
				 SELECT PENSION_INST_NAME
				 INTO
				    v_descr
				 FROM
				    COM_PENSION_INSTITUTIONS
				 WHERE
				    PENSION_INST_CODE = v_value AND
				    ROWNUM = 1;
				    
			END IF;
  END IF;
	RETURN 	v_descr;

EXCEPTION
 WHEN NO_DATA_FOUND THEN
   RETURN null;		
end;

function CF_KATIGORIA_SYNTAXHSFormula return Char is v_title_code VARCHAR2(5); v_value VARCHAR2(50); v_descr VARCHAR2(150); begin
IF :P_ACCOUNT_MAIN IS NOT NULL THEN SELECT PROCUCT_DESCRIPTION INTO v_descr FROM PEN_ACCOUNT a, PEN_QC_PER_PRODINST b, PEN_PRODUCT_PER_INSTITUTIONS c, PEN_PRODUCTS d WHERE a.QCPRODINS_QC_PER_PRODINST_CODE = b.QC_PER_PRODINST_CODE AND b.PRODUCT_PER_INSTITUTION_CODE = c.PRODUCT_PER_INSTITUTION_CODE AND c.PRODUCT_CODE = d.PRODUCT_CODE AND a.account_no = :P_ACCOUNT_MAIN; ELSE v_title_code := '00075'; v_value:= (FIND_FACT_SUB_DEATH_VARCHAR(:P_INSURED_ID_IND, :P_DT_DECISION_YEAR_SR, :P_DT_DEC_UNIT_CODE_SR, :P_DT_INCR_SEC_NO_SR, '1', 0, 0, '00001', v_title_code, '00011')); IF v_value IS NOT NULL THEN SELECT PROCUCT_DESCRIPTION INTO v_descr FROM PEN_PRODUCTS WHERE PRODUCT_CODE = v_value AND ROWNUM = 1;
END IF; END IF;
RETURN v_descr;
EXCEPTION WHEN NO_DATA_FOUND THEN RETURN null; end;

      function CF_BASIKOS_MISTHOSFormula return Number is
 v_title_code VARCHAR2(5); 
 v_value VARCHAR2(50);
 v_descr VARCHAR2(150);
 v_dt_decision_year   PEN_DECISION_INSTANCE.DECISION_YEAR_SR%TYPE;
 v_dt_dec_unit_code   PEN_DECISION_INSTANCE.DEC_UNIT_CODE_SR%TYPE;
 v_DEC_INCR_SEC_NO_SR PEN_DECISION_INSTANCE.INCR_SEQ_NO_SR%TYPE;
begin
  
  IF :P_ACCOUNT_MAIN IS NOT NULL THEN
  	v_title_code := '00031';  
    v_dt_decision_year   := :p_main_decision_year_sr;
    v_dt_dec_unit_code   := :p_main_dec_unit_code_sr;
    v_DEC_INCR_SEC_NO_SR := :P_main_incr_seq_no_sr;
  ELSE
  	v_title_code := '00075';
  	v_dt_decision_year   := :P_DT_DECISION_YEAR_SR;
    v_dt_dec_unit_code   := :P_DT_DEC_UNIT_CODE_SR;
    v_DEC_INCR_SEC_NO_SR := :P_DT_INCR_SEC_NO_SR;
  END IF; 
	v_value:=  (FIND_FACT_SUB_DEATH_VARCHAR(:P_INSURED_ID_IND,
					                            v_dt_decision_year, --:P_DT_DECISION_YEAR_SR,
					                            v_dt_dec_unit_code, --:P_DT_DEC_UNIT_CODE_SR,
								                      v_DEC_INCR_SEC_NO_SR, --:P_DT_INCR_SEC_NO_SR,
								                      '1',
								                      0,
									                    0,
									                    '00001',
									                    v_title_code,
	                							      '00048'));						      
	 RETURN TO_NUMBER(v_value);	
end;

