      function CF_AITIA_EXODOUFormula return Char is
 v_title_code VARCHAR2(5); 
 v_value VARCHAR2(50);
 v_descr VARCHAR2(250);
begin
  
  v_descr := null;
  v_title_code := '00074'; 
	v_value:=  (FIND_FACT_SUB_DEATH_VARCHAR(:P_INSURED_ID,
	                                    :P_DT_DECISION_YEAR_DIR,
					                            :P_DT_DEC_UNIT_CODE_DIR,
								                      :P_DT_INCR_SEC_NO_DIR,
								                      '1',
								                      0,
									                    0,
									                    '00001',
									                    v_title_code,
	                							      '00130'));						      
	
	IF v_value IS NOT NULL THEN
  	 SELECT 
          EXIT_CAUSE_DESCR
     INTO 
        v_descr
     FROM
        PEN_ETEAM_EXIT_CAUSE
     WHERE
        EXIT_CAUSE_CODE = v_value;	 
  END IF;
  
  RETURN v_descr;
  

EXCEPTION 
WHEN NO_DATA_FOUND THEN
     RETURN null;		
end;

function CF_LYSH_YPAL_SXESHSFormula return Char is v_title_code VARCHAR2(5); v_value VARCHAR2(50); v_descr VARCHAR2(150);
CURSOR CUR_VALUE IS SELECT VALUE FROM PEN_DEC_FACT_TYPES_INSTANCE WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_DIR AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_DIR AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_DIR AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND --PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_INSURED_ID AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = v_title_code AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00211';
begin
v_title_code := '00031'; OPEN CUR_VALUE; FETCH CUR_VALUE INTO v_value; CLOSE CUR_VALUE; /* v_value:= (FIND_FACT_SUB_DEATH_VARCHAR(:P_INSURED_ID, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '00001', v_title_code, '00211')); */ RETURN v_value;
end;

      function CF_YEARS_REQUIRED2Formula return Number is
 v_ret NUMBER;
begin
  	v_ret := NVL(TRUNC(:P_REQUIRED_DAYS / 300),0);
  	RETURN v_ret;
end;

      function CF_MONTHS_REQUIRED2Formula return Number is
  v_ret NUMBER;
begin
  	v_ret := TRUNC((:P_REQUIRED_DAYS - (300 * :CF_YEARS_REQUIRED2)) /25);
  	RETURN v_ret;
end;

      function CF_DAYS_REQUIRED2Formula return Number is
  v_ret NUMBER;
begin
	
	IF :P_REQUIRED_DAYS >= 25 THEN
     v_ret := (TRUNC(:P_REQUIRED_DAYS - (300 * :CF_YEARS_REQUIRED2) - (25 * :CF_MONTHS_REQUIRED2)));
	ELSE
		 v_ret := :P_REQUIRED_DAYS;
	END IF;
	
