      function CF_PROTOCOL_CASE2Formula return Char is
v_value   VARCHAR2(50);
v_DISPLAY VARCHAR2(20); 
--v_title_code VARCHAR2(5); 

begin

v_value:=  (FIND_FACT_SUB_DEATH_VARCHAR(:P_INSURED_ID,
					                            :P_DT_DECISION_YEAR_DIR,
					                            :P_DT_DEC_UNIT_CODE_DIR,
								                      :P_DT_INCR_SEC_NO_DIR,
								                      '1',
								                      0,
									                    0,
									                    '00001',
									                    '00031',
									                    '00064'));
	 
	IF :PRODUCT_CODE='00003' THEN
		IF :SEX='Α' THEN
		  V_DISPLAY:='του ασφαλισμένου';
	  end if;
	  IF :SEX='Θ' THEN
		  V_DISPLAY:='της ασφαλισμένης';
	  end if;
  END IF;

	IF :PRODUCT_CODE='00004' THEN
		IF :SEX='Α' THEN
		  V_DISPLAY:='του συνταξιούχου';
	  end if;
	  IF :SEX='Θ' THEN
		  V_DISPLAY:='της συνταξιούχου';
	  end if;
	END IF; 

IF V_VALUE IN (14,15) THEN
	 RETURN 'για μεταβίβαση της ΣΥΝΤΑΞΗΣ κατά το Αρ. 64 του Α.Ν. 1854/1951';
ELSE
  IF :CF_AWARD_FLG='0' THEN 
  	  RETURN 'για απονομή της ' ||:CF_SEX || ' με τα κάτωθι στοιχεία:';
  ELSE                                    
  	IF :PROTOCOL_NO IS NOT NULL THEN 
  	  RETURN 'για τροποποίηση της πράξης απονομής σύνταξης λόγω Θανάτου ' || V_DISPLAY || ' με τα κάτωθι στοιχεία:';
  	ELSE
  		RETURN 'για την οίκοθεν τροποποίηση της πράξης απονομής σύνταξης λόγω Θανάτου ' || V_DISPLAY || ' με τα κάτωθι στοιχεία:';
  	END IF;
  END IF;
 END IF; 
  
end;

