function CF_11Formula return Number is V_AMOUNT NUMBER;
CURSOR CUR_FIND IS SELECT PEN_ACCOUNT.SECURED_AMOUNT_FOR_REIN FROM REG_INSURED, PEN_APPLICATION_INSTANCES, COM_ORG_BRANCHES, PEN_BE_PER_PRODINST, PEN_PRODUCT_PER_INSTITUTIONS, PEN_PRODUCTS, COM_PENSION_IKA_INSTITUTION, PEN_ACCOUNT WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID AND PEN_BE_PER_PRODINST.BE_PER_PRODINST_CODE=:P_BE_PER_PRODINST AND PEN_BE_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE_SR AND PEN_ACCOUNT.ACCOUNT_NO= :P_ACC_ACCOUNT_NO_DIR;
BEGIN OPEN CUR_FIND; FETCH CUR_FIND INTO V_AMOUNT; IF CUR_FIND%NOTFOUND THEN CLOSE CUR_FIND; ELSE RETURN V_AMOUNT; END IF;
end;

