      function CF_51Formula return Date is
V_DATE	DATE;
V_WAGE_SCALE	NUMBER;

CURSOR CUR_WAGE_SCALE IS
SELECT DT_START, 
			 WAGE_SCALE
FROM PEN_AVERAGE_WAGE_PER_INS_2008
WHERE INS_INSURED_ID = :P_INSURED_ID
ORDER BY DT_START DESC;

begin
  
  OPEN CUR_WAGE_SCALE;
  FETCH CUR_WAGE_SCALE
  INTO V_DATE, 
  		 V_WAGE_SCALE;
  CLOSE CUR_WAGE_SCALE;
  
  IF V_WAGE_SCALE IS NOT NULL THEN
  	RETURN V_DATE;
  ELSE
		RETURN NULL;
  END IF;
  
end;

