      function CF_lektikoFormula return Char is




begin
	
	declare
		
		
		CURSOR Cur_Sp_Fact_00538 IS
  SELECT VALUE
	FROM 
	   PEN_DEC_FACT_TYPES_INSTANCE a
	WHERE
	a.DI_DEC_INCR_SEQ_NO_SR =  	:P_DT_INCR_SEC_NO_SR AND
	a.DI_DECISION_YEAR_SR = 		:P_DT_DECISION_YEAR_SR AND
	a.DI_DEC_UNIT_CODE_SR =  		:P_DT_DEC_UNIT_CODE_SR AND
	a.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND
	   a.Title_Code         = '00374' AND
	   a.Dec_Fact_Type_Code = '00538';
	 							                      
	
	my_value varchar2(1);
	
	
	begin
		
	
		
open Cur_Sp_Fact_00538;
fetch Cur_Sp_Fact_00538
into my_value;
close Cur_Sp_Fact_00538;
    
  
    
	if my_value='1' then
		:cp_new_amount:=:p_pension_amount*0.3;
		Return 'ΤΟ ΠΟΣΟ ΜΕΙΩΝΕΤΑΙ ΚΑΤΑ 70% ΛΟΓΩ ΕΡΓΑΣΙΑΣ ΣΤΟ ΔΗΜΟΣΙΟ';
	ELSE
		:cp_new_amount:=:p_pension_amount;
		Return '';
	end if;	
	
	
	end;	
		
  
end;

      function CF_MIN_MAX_DATESFormula return Char is
begin
  
  DECLARE
  	
  	CURSOR DATES IS 
  	SELECT MIN(DT_START),MAX(DT_END) 
		FROM PEN_AVERAGE_WAGE_PER_INS_2008 FF 
		WHERE FF.INS_INSURED_ID=:P_INSURED_ID;
		
		
		MY_DT_START DATE;
		MY_DT_END		DATE;

BEGIN		
		
		IF NVL(:TOTAL_AMOUNT_2008,0) != '0' THEN
		
		
		
		
		OPEN DATES;
		FETCH DATES
		INTO MY_DT_START,MY_DT_END;
		CLOSE DATES;
		
		RETURN 'ΑΠΟ '||''||MY_DT_START||' ΕΩΣ '||MY_DT_END;
		
		ELSE
		
		RETURN '';
		
		END IF;
			
  END;
  
  
end;

